import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Input, SearchInput, addToast, localInputToISOWithOffset } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import { createFixedAssetSearchConfig } from '../../../components/search';
import { DocumentFormHeader } from '../../../components/layout';
import df from '../../../styles/documentForm.module.css';

const TEST_ID = 'tscd-thoi-khau-hao';

const TscdThoiKhauHaoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const assetSearchConfig = useMemo(() => createFixedAssetSearchConfig(), []);
  const [fixedAssetId, setFixedAssetId] = useState('');
  const [assetCode, setAssetCode] = useState('');
  const [stopDate, setStopDate] = useState(new Date().toISOString().slice(0, 10));
  const [note, setNote] = useState('');
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    if (!fixedAssetId) {
      dispatch(addToast({ message: 'TSCĐ là bắt buộc', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      await tscdService.suspendDepreciation({
        fixedAssetId,
        stopDate: localInputToISOWithOffset(stopDate),
        note: note || undefined,
      });
      dispatch(addToast({ message: 'Thôi khấu hao thành công', type: 'success' }));
      navigate('/tscd/danh-sach');
    } catch (e: unknown) {
      dispatch(addToast({ message: e instanceof Error ? e.message : 'Lỗi thôi khấu hao', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={df.page} data-testid={`${TEST_ID}-form`}>
      <DocumentFormHeader
        onBack={() => navigate('/tscd/danh-sach')}
        title="Thôi khấu hao"
        isNew
        saving={saving}
        saveLabel="Xác nhận"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin thôi khấu hao</h2>
        <div className={df.row4}>
          <div className={df.spanCol2} data-testid={`${TEST_ID}-field-fixedAssetId`}>
            <label className={df.label}>TSCĐ *</label>
            <SearchInput
              config={assetSearchConfig}
              value={fixedAssetId}
              primaryDisplay={assetCode}
              onChange={a => { setFixedAssetId(a.id); setAssetCode(a.code); }}
              onClear={() => { setFixedAssetId(''); setAssetCode(''); }}
              showLabel={false}
              showSecondaryInput={false}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Ngày thôi KH</label>
            <Input type="date" value={stopDate} onChange={e => setStopDate(e.target.value)} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Ghi chú</label>
            <Input value={note} onChange={e => setNote(e.target.value)} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default TscdThoiKhauHaoPage;
